<!doctype html><html lang="es"><head><meta charset="utf-8"><style>@page{margin:0}*{box-sizing:border-box}body{margin:0;font-family:Arial,sans-serif;color:#172554}.page{width:100%;height:100vh;padding:34px;background:linear-gradient(135deg,#1e3a8a,#2563eb 58%,#7c3aed)}.inner{height:100%;background:white;border-radius:18px;padding:58px 76px;text-align:center;position:relative}.eyebrow{font-size:14px;letter-spacing:4px;text-transform:uppercase;color:#2563eb;font-weight:bold}.title{font-size:48px;margin:20px 0 14px}.copy{font-size:18px;color:#64748b}.student{font-size:40px;font-weight:bold;margin:28px 0 8px;color:#1e3a8a}.course{font-size:27px;color:#7c3aed;font-weight:bold}.meta{display:flex;justify-content:center;gap:70px;margin-top:34px;font-size:14px;color:#64748b}.qr{position:absolute;right:54px;bottom:40px;width:105px}.brand{position:absolute;left:60px;bottom:52px;font-size:20px;font-weight:bold}.code{position:absolute;left:0;right:0;bottom:24px;font-size:10px;color:#94a3b8}</style></head><body><div class="page"><div class="inner"><div class="eyebrow">Certificado de finalización</div><div class="title">Reconocemos tu logro</div><div class="copy">Se certifica que</div><div class="student">{{ $certificate->student->name }}</div><div class="copy">completó satisfactoriamente el curso</div><div class="course">{{ $certificate->course->title }}</div><div class="meta"><span>Emitido: {{ $certificate->issued_at->format('d/m/Y') }}</span><span>Progreso: 100%</span></div><div class="brand">AulaPro</div>@if($certificate->qr_code_path)<img class="qr" src="{{ storage_path('app/public/'.$certificate->qr_code_path) }}">@endif<div class="code">{{ $certificate->certificate_code }}</div></div></div></body></html>
